import subprocess
import sys
import shutil
import os

def install_dependencies():
    """Installs project dependencies from requirements.txt."""
    print("Installing dependencies from requirements.txt...")
    try:
        subprocess.run([sys.executable, "-m", "pip", "install", "-r", "requirements.txt"], check=True)
        print("Dependencies installed successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Error installing dependencies: {e}", file=sys.stderr)
        sys.exit(1)

def run_tests():
    """Runs application tests."""
    print("Running application tests...")
    # Assuming tests can be run with 'pytest' or similar.
    # Adjust this command based on your testing framework.
    try:
        # Example using pytest. Adjust if you use a different test runner (e.g., unittest, nose)
        # or if your tests need specific arguments.
        subprocess.run([sys.executable, "-m", "pytest"], check=True)
        print("Tests passed successfully.")
    except FileNotFoundError:
        print("Pytest not found. Please ensure it's installed or adjust the test command.", file=sys.stderr)
        sys.exit(1)
    except subprocess.CalledProcessError as e:
        print(f"Tests failed: {e}", file=sys.stderr)
        sys.exit(1)

def package_for_deployment(project_name="my_application"):
    """
    Packages the application for deployment.
    This example creates a simple zip archive of the project directory.
    For more complex applications, consider using wheel, Docker, or other packaging tools.
    """
    print(f"Packaging application '{project_name}' for deployment...")
    current_dir = os.getcwd()
    deployment_package_dir = os.path.join(current_dir, "deployment_package")
    output_archive_name = f"{project_name}_deployment"

    # Clean up previous package directory
    if os.path.exists(deployment_package_dir):
        shutil.rmtree(deployment_package_dir)

    # Create a temporary directory for the package contents
    os.makedirs(deployment_package_dir)

    # List of items to include in the package
    # Customize this list based on what your application needs to run
    items_to_include = [
        "app", # Your application code directory
        "requirements.txt",
        "main.py", # Your main entry point
        # Add other essential files/directories here (e.g., static, templates, config)
    ]

    # Copy files/directories into the deployment package directory
    for item in items_to_include:
        src_path = os.path.join(current_dir, item)
        dst_path = os.path.join(deployment_package_dir, item)
        if os.path.exists(src_path):
            if os.path.isdir(src_path):
                shutil.copytree(src_path, dst_path, dirs_exist_ok=True)
            else:
                shutil.copy2(src_path, dst_path)
        else:
            print(f"Warning: Item '{item}' not found for packaging.", file=sys.stderr)

    # Create the zip archive
    try:
        shutil.make_archive(output_archive_name, 'zip', root_dir=current_dir, base_dir="deployment_package")
        print(f"Application packaged successfully: {output_archive_name}.zip")
    except Exception as e:
        print(f"Error packaging application: {e}", file=sys.stderr)
        sys.exit(1)
    finally:
        # Clean up the temporary package directory
        if os.path.exists(deployment_package_dir):
            shutil.rmtree(deployment_package_dir)

if __name__ == "__main__":
    print("--- Starting Deployment Workflow ---")

    install_dependencies()
    run_tests()
    package_for_deployment()

    print("--- Deployment Workflow Completed Successfully ---")